function AppLogo({className='appLogo'}:{className?:string}){return <img className={className} src="/branding/logo-app.png" alt="Diário de Bordo Trevo"/>}
function Login({onOk}:{onOk:()=>void}){const[u,setU]=useState('ana.peliteiro'),[s,setS]=useState('admin123'),[err,setErr]=useState('');async function go(e:any){e.preventDefault();setErr('');try{await login(u,s);onOk()}catch(x:any){setErr(x.message||'Usuário, senha ou status inválido.')}}return <div className="login"><div className="loginPanel"><div className="brand"><AppLogo className="loginLogo"/><h1>Diário de Bordo Trevo</h1><p>Operação conectada e rastreável.</p></div><form className="card loginCard" onSubmit={go}><label>Usuário<input value={u} onChange={e=>setU(e.target.value)} placeholder="ana.peliteiro" autoCapitalize="none" autoCorrect="off"/></label><label>Senha<input type="password" value={s} onChange={e=>setS(e.target.value)}/></label>{err&&<div className="err">{err}</div>}<button className="primary">Entrar</button></form></div></div>}
function Shell(){
  const[tab,setTab]=useState('home'),[online,setOnline]=useState(navigator.onLine),[tick,setTick]=useState(0),[profileOpen,setProfileOpen]=useState(false),[dark,setDark]=useState(localStorage.getItem('dbt_theme')==='dark'),[editing,setEditing]=useState<Diario|null>(null);
  useEffect(()=>{document.body.classList.toggle('darkTheme',dark);localStorage.setItem('dbt_theme',dark?'dark':'light')},[dark]);
  useEffect(()=>{const a=()=>{setOnline(true);syncPending().finally(()=>setTick(t=>t+1))},b=()=>setOnline(false);addEventListener('online',a);addEventListener('offline',b);return()=>{removeEventListener('online',a);removeEventListener('offline',b)}},[]);
  async function sync(){await syncPending();setTick(t=>t+1)}
  function editRecord(d:Diario){setEditing(d);setTab('novo')}
  const me=currentUser()!;
  return <><header className="topbar"><button className="logoButton" onClick={()=>setProfileOpen(true)} aria-label="Abrir menu do perfil"><AppLogo className="miniLogoImg"/></button><div className="appIdentity"><div><b>Diário de Bordo Trevo</b><span>{me.nome} • {me.perfil}</span></div></div><div className={online?'pill ok':'pill bad'}>{online?<Wifi size={14}/>:<WifiOff size={14}/>} {online?'Online':'Offline'}</div></header><main>{tab==='home'&&<HomePage tick={tick} onEdit={editRecord}/>} {tab==='novo'&&<NovoDiario editing={editing} onSaved={()=>{setEditing(null);setTick(t=>t+1);setTab('home')}}/>} {tab==='historico'&&<Historico onEdit={editRecord}/>} {tab==='admin'&&<Admin/>}</main><nav className="bottomNav"><button onClick={()=>{setEditing(null);setTab('home')}} className={tab==='home'?'active':''}><Home/>Hoje</button><button onClick={()=>{setEditing(null);setTab('novo')}} className={tab==='novo'?'active':''}><Plus/>Novo</button><button onClick={()=>{setEditing(null);setTab('historico')}} className={tab==='historico'?'active':''}><History/>Histórico</button>{isAdmin()&&<button onClick={()=>{setEditing(null);setTab('admin')}} className={tab==='admin'?'active':''}><Users/>Admin</button>}</nav><ProfileDrawer open={profileOpen} onClose={()=>setProfileOpen(false)} onSync={sync} dark={dark} setDark={setDark}/></>}
function ProfileDrawer({open,onClose,onSync,dark,setDark}:{open:boolean;onClose:()=>void;onSync:()=>void;dark:boolean;setDark:(v:boolean)=>void}){const me=currentUser()!;const[showProfile,setShowProfile]=useState(false),[showPassword,setShowPassword]=useState(false),[senha,setSenha]=useState(''),[senha2,setSenha2]=useState(''),[msg,setMsg]=useState('');if(!open)return null;async function trocarSenha(){if(senha.length<6)return setMsg('A senha precisa ter no mínimo 6 caracteres.');if(senha!==senha2)return setMsg('As senhas não conferem.');await saveUsuario({id:me.id,senha,trocar_senha:false});setSenha('');setSenha2('');setMsg('Senha alterada com sucesso.')}return <div className="drawerBackdrop" onClick={onClose}><aside className="profileDrawer" onClick={e=>e.stopPropagation()}><div className="drawerHeader"><AppLogo className="drawerLogoImg"/><button className="iconBtn" onClick={onClose}><X size={20}/></button></div><h2>{me.nome}</h2><p>{me.usuario} • {me.perfil}</p><div className="drawerMeta"><span>{me.setor}</span><span>{me.cargo}</span></div><div className="drawerActions"><button className="drawerAction" onClick={()=>setShowProfile(!showProfile)}><UserRound size={18}/> Meu Perfil</button><button className="drawerAction" onClick={()=>setShowPassword(!showPassword)}><KeyRound size={18}/> Alterar Senha</button><button className="drawerAction" onClick={onSync}><RefreshCcw size={18}/> Sincronizar agora</button><button className="drawerAction" onClick={()=>setDark(!dark)}>{dark?<Sun size={18}/>:<Moon size={18}/>} {dark?'Tema claro':'Tema escuro'}</button><button className="drawerAction dangerLine" onClick={()=>{logout();location.reload()}}><LogOut size={18}/> Sair</button></div>{showProfile&&<div className="drawerPanel"><b>Meu Perfil</b><p><strong>Nome:</strong> {me.nome}</p><p><strong>Usuário:</strong> {me.usuario}</p><p><strong>Setor:</strong> {me.setor}</p><p><strong>Cargo:</strong> {me.cargo}</p><p><strong>Perfil:</strong> {me.perfil}</p></div>}{showPassword&&<div className="drawerPanel"><b>Alterar Senha</b><label>Nova senha<input type="password" value={senha} onChange={e=>setSenha(e.target.value)} placeholder="mínimo 6 caracteres"/></label><label>Confirmar senha<input type="password" value={senha2} onChange={e=>setSenha2(e.target.value)} /></label>{msg&&<div className="hint">{msg}</div>}<button className="primary" onClick={trocarSenha}><Save size={18}/> Salvar nova senha</button></div>}</aside></div>}

type AreaEnvase='Envase 1'|'Envase 2';
type ViewMode='maquina'|'turno';
type CritFilter='todos'|'desvios'|'atencoes';
type PcpStatus='sim'|'nao';
type MachineEntry={
  maquina:string; pcpStatus:PcpStatus; motivo?:string; ocorrido?:string; skuAtual:string; skuProgramado?:string; programado:string; produzido:string; proximosSkus?:string; novaSequencia?:string;
  ultimoCip:string; proximoCip:string; fezCip:'sim'|'nao'; cipRealizadoEm?:string; parada4h:'sim'|'nao'; paradaInicio?:string; paradaFim?:string; paradaMotivo?:string; cipRenovacao?:'sim'|'nao'; cipRenovacaoEm?:string; cipMotivo?:string;
  pessoas?:string; observacoes:string;
};
type PassagemV6={version:'v6-envase';area:AreaEnvase;turno:string;data:string;lider:string;liderId:string;criadoEm:string;maquinas:MachineEntry[];observacoesGerais:string};
type DraftPublicMeta={version:'draft-v2';area:AreaEnvase;turno:string;data:string;responsavelId:string;responsavelNome:string;activeMachine:string;concluidas:number;total:number;atualizadoEm:string};
type DraftEnvelope={meta:DraftPublicMeta;payload?:{area:AreaEnvase;turno:string;data:string;obs:string;entries:MachineEntry[];activeMachine:string}};
type OperationalItem={record:Diario;payload:PassagemV6;machine:MachineEntry;status:'conforme'|'atencao'|'desvio';reason:string;turno:string;area:AreaEnvase;machineName:string;criadoEm:string;lider:string};
const V6_PREFIX='V6_ENVASE_JSON:';
const DRAFT_PREFIX='V6_DRAFT_META:';
const DEFAULT_MACHINES:Record<AreaEnvase,string[]>={
  'Envase 1':['Braskop 1','Braskop 2','Braskop 3','Dmax 6','Serac 1','Serac 2'],
  'Envase 2':['Dmax 1','Dmax 2','Dmax 3','Dmax 4','Gualapack','TBA 1','TBA 2']
};
const MOTIVOS_DESVIO=['Manutenção / quebra','Falta de material','Aguardando qualidade','Setup atrasado','Reprogramação PCP','Falta de pessoas','Atraso base','Padronização','Reprocesso','Outro'];
function toLocalDateInput(d=new Date()){const pad=(n:number)=>String(n).padStart(2,'0');return`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`}
function toLocalDateTimeInput(d=new Date()){const pad=(n:number)=>String(n).padStart(2,'0');return`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`}
function isFutureDate(value:string){return!!value&&value>toLocalDateInput()}
function isFutureDateTime(value:string){if(!value)return false;const d=new Date(value);return!Number.isNaN(d.getTime())&&d.getTime()>Date.now()}
function plusHoursLocal(value:string,hours:number){if(!value)return'';const d=new Date(value);if(Number.isNaN(d.getTime()))return'';return toLocalDateTimeInput(new Date(d.getTime()+hours*60*60*1000))}
function fmtDateTime(v?:string){if(!v)return'—';const d=new Date(v);return Number.isNaN(d.getTime())?v:d.toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'})}
function fmtShort(v?:string){if(!v)return'—';const d=new Date(v);return Number.isNaN(d.getTime())?v:d.toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}
function fmtFormDateTime(v?:string){if(!v)return'';const d=new Date(v);return Number.isNaN(d.getTime())?v:d.toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'}).replace(',', ' •')}
function fmtDateDash(v?:string){if(!v)return'—';const raw=String(v).slice(0,10);const m=raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);return m?`${m[3]}-${m[2]}-${m[1]}`:raw}
function InlineFieldError({message}:{message?:string}){return message?<span className="inlineFieldError">{message}</span>:null}
function formatQuantity(value:string){const digits=value.replace(/\D/g,'').replace(/^0+(?=\d)/,'');if(!digits)return'';return Number(digits).toLocaleString('pt-BR')}
function parsePassagem(d:Diario):PassagemV6|null{try{if(!d.resumo?.startsWith(V6_PREFIX))return null;return JSON.parse(d.resumo.slice(V6_PREFIX.length))}catch{return null}}
function parseDraftEnvelope(d:Diario):DraftEnvelope|null{try{if(!d.resumo?.startsWith(DRAFT_PREFIX))return null;const raw=JSON.parse(d.resumo.slice(DRAFT_PREFIX.length));if(raw?.meta)return raw as DraftEnvelope;return{meta:raw as DraftPublicMeta}}catch{return null}}
function parseDraftMeta(d:Diario):DraftPublicMeta|null{return parseDraftEnvelope(d)?.meta||null}
function draftStorageKey(userId:string,data:string,turno:string,area:AreaEnvase){return`dbt_v682_draft_${userId}_${data}_${turno.replace(/\s+/g,'_')}_${area.replace(/\s+/g,'_')}`}
function isFinalized(d:Diario){return ['finalizado','finalizada'].includes(String(d.status||'').toLowerCase())}
function isInProgress(d:Diario){return String(d.status||'').toLowerCase()==='em preenchimento'}
function classifyMachine(m:MachineEntry){const now=new Date();const next=m.proximoCip?new Date(m.proximoCip):null;const cipVencido=!!next&&!Number.isNaN(next.getTime())&&next<now;const venceLogo=!!next&&!Number.isNaN(next.getTime())&&next>=now&&(next.getTime()-now.getTime())<=12*60*60*1000;if(m.pcpStatus==='nao')return{status:'desvio' as const,reason:m.motivo||'PCP não seguido'};if(cipVencido)return{status:'desvio' as const,reason:'CIP vencido'};if(m.parada4h==='sim'&&m.cipRenovacao==='nao')return{status:'desvio' as const,reason:'Parada ≥4h sem CIP de renovação'};if(venceLogo)return{status:'atencao' as const,reason:'CIP vence em até 12h'};if(m.parada4h==='sim')return{status:'atencao' as const,reason:'Parada ≥4h registrada'};if((m.pessoas||'').trim())return{status:'atencao' as const,reason:'Aviso de pessoas/trocas'};return{status:'conforme' as const,reason:'Sem pendências'}}

function focusNextControl(current:HTMLElement|null){
  if(!current)return;
  const form=current.closest('.quickFormCard')||current.closest('.opGroupBody')||current.closest('section')||document.body;
  const controls=Array.from(form.querySelectorAll<HTMLElement>('input:not([readonly]), select, textarea, button.skuTrigger, button.primary'))
    .filter(el=>!el.hasAttribute('disabled')&&el.offsetParent!==null);
  const choiceGroup=current.closest('.choiceButtons');
  const anchor=choiceGroup?(choiceGroup.querySelectorAll<HTMLElement>('button').item(choiceGroup.querySelectorAll('button').length-1)||current):current;
  const idx=controls.indexOf(anchor);
  if(idx>=0&&idx<controls.length-1){
    setTimeout(()=>{
      const nextControl=controls[idx+1];
      nextControl.scrollIntoView({behavior:'smooth',block:'center'});
      nextControl.focus({preventScroll:true});
      if(nextControl instanceof HTMLInputElement)nextControl.select();
    },100);
  }
}
function nextOnEnter(e:React.KeyboardEvent<HTMLElement>){
  if(e.key==='Enter'){
    e.preventDefault();
    focusNextControl(e.currentTarget);
  }
}
function nextAfterChange(el:HTMLElement){setTimeout(()=>focusNextControl(el),100)}
function SkuSelect({value,onChange,label,machine,autoAdvance=true}:{value:string;onChange:(v:string)=>void;label:string;machine:string;autoAdvance?:boolean}){
  const options=useMemo(()=>skuOptionsForMachine(machine),[machine]);
  const[query,setQuery]=useState('');
  const[open,setOpen]=useState(false);
  const triggerRef=useRef<HTMLButtonElement|null>(null);
  const searchRef=useRef<HTMLInputElement|null>(null);
  const filtered=useMemo(()=>{
    const q=query.trim().toLocaleLowerCase('pt-BR');
    if(!q)return options;
    return options.filter(item=>item.toLocaleLowerCase('pt-BR').includes(q));
  },[options,query]);
  useEffect(()=>{
    if(!open)return;
    const old=document.body.style.overflow;
    document.body.style.overflow='hidden';
    const id=setTimeout(()=>searchRef.current?.focus(),100);
    return()=>{clearTimeout(id);document.body.style.overflow=old};
  },[open]);
  function close(){setOpen(false);setQuery('')}
  function choose(item:string){
    onChange(item);
    close();
    if(autoAdvance)setTimeout(()=>focusNextControl(triggerRef.current),140);
  }
  const modal=open?createPortal(<div className="skuModal" role="dialog" aria-modal="true" aria-label={`Selecionar ${label}`}>
    <div className="skuModalHeader"><div><small>{machine}</small><h3>{label}</h3></div><button type="button" className="iconBtn skuModalClose" onClick={close}><X size={22}/></button></div>
    <div className="skuModalSearch"><Search size={20}/><input ref={searchRef} value={query} onChange={e=>setQuery(e.target.value)} placeholder="Digite nome ou código do SKU" inputMode="search" enterKeyHint="search"/></div>
    <div className="skuModalHint">Toque em uma opção para selecionar e seguir automaticamente.</div>
    <div className="skuModalList" role="listbox">{filtered.length?filtered.map(item=><button type="button" key={item} className={item==='Sem Programação'?'skuModalOption noSchedule':'skuModalOption'} onClick={()=>choose(item)}>{item}</button>):<div className="skuEmpty">Nenhum SKU encontrado.</div>}</div>
  </div>,document.body):null;
  return <label className="skuField">{label}<button ref={triggerRef} type="button" className="skuTrigger" onClick={()=>setOpen(true)} aria-haspopup="dialog"><span className={value?'':'placeholder'}>{value||'Toque para selecionar o SKU'}</span><Search size={18}/></button>{modal}</label>
}
function operationalItems(diarios:Diario[], period?:(d:Diario)=>boolean):OperationalItem[]{const list:OperationalItem[]=[];diarios.filter(d=>period?period(d):true).forEach(d=>{const p=parsePassagem(d);if(!p)return;p.maquinas.forEach(m=>{const c=classifyMachine(m);list.push({record:d,payload:p,machine:m,status:c.status,reason:c.reason,turno:p.turno,area:p.area,machineName:m.maquina,criadoEm:p.criadoEm,lider:p.lider})})});return list.sort((a,b)=>new Date(b.criadoEm).getTime()-new Date(a.criadoEm).getTime())}
function latestItems(items:OperationalItem[]){const map=new Map<string,OperationalItem>();items.forEach(i=>{const k=`${i.area}|${i.machineName}|${i.turno}`;if(!map.has(k))map.set(k,i)});return Array.from(map.values())}
function StatusPill({status}:{status:OperationalItem['status']}){return <span className={'opPill '+status}>{status==='desvio'?'Desvio':status==='atencao'?'Atenção':'Conforme'}</span>}
function MachineDetail({item}:{item:OperationalItem}){const m=item.machine;return <div className="opDetailGrid"><div><small>PCP</small><b>{m.pcpStatus==='sim'?'Conforme':'Não conforme'}</b></div>{m.pcpStatus==='nao'&&<><div><small>Motivo</small><b>{m.motivo||'—'}</b></div><div><small>SKU programado</small><b>{m.skuProgramado||'—'}</b></div></>}<div><small>SKU atual</small><b>{m.skuAtual}</b></div>{m.skuAtual!=='Sem Programação'&&<><div><small>Programado</small><b>{m.programado}</b></div><div><small>Produzido</small><b>{m.produzido}</b></div></>}<div className="span2"><small>Próximos SKUs / Sequência</small><b>{m.pcpStatus==='nao'?(m.novaSequencia||'—'):(m.proximosSkus||'—')}</b></div><div><small>Último CIP</small><b>{fmtShort(m.ultimoCip)}</b></div><div><small>Próximo CIP</small><b>{fmtShort(m.proximoCip)}</b></div><div><small>Fez CIP?</small><b>{m.fezCip==='sim'?'Sim':'Não'}</b></div><div><small>Parada ≥4h</small><b>{m.parada4h==='sim'?'Sim':'Não'}</b></div>{m.parada4h==='sim'&&<><div><small>CIP de renovação</small><b>{m.cipRenovacao==='sim'?'Sim':'Não'}</b></div><div className="span2"><small>Motivo parada/CIP</small><b>{m.paradaMotivo||m.cipMotivo||'—'}</b></div></>}<div className="span2"><small>Pessoas/trocas/avisos</small><b>{m.pessoas||'Sem trocas/avisos de pessoas.'}</b></div><div className="span2 opObs"><small>Observações</small><b>{m.observacoes||'Sem observações gerais.'}</b></div><div className="span2"><small>Registro</small><b>{item.lider} • {fmtDateTime(item.record.criado_em||item.criadoEm)}</b>{item.record.editado&&<span className="editMeta">Última atualização: {item.record.ultima_edicao_por||item.lider} • {fmtDateTime(item.record.ultima_edicao_em||item.record.atualizado_em)}</span>}</div></div>}
